import { isIndicatorPartiallyOrWithinDomain } from './is-indicator-partially-or-within-domain.js';
import { isRangeMarker } from '../../../utils/is-range-marker.js';
import { IndicatorData } from '../types.js';

export function filterIndicatorsOutOfBounds(
  indicators: IndicatorData[][],
  [domainStart, domainEnd]: number[],
): IndicatorData[][] {
  const filteredIndicators: IndicatorData[][] = [];

  indicators.forEach((track, index) => {
    filteredIndicators[index] = track.filter((indicator) => {
      const { start } = indicator;
      const indicatorStart = start.valueOf();

      if (isRangeMarker(indicator)) {
        const { end } = indicator;
        const indicatorEnd = end.valueOf();

        return isIndicatorPartiallyOrWithinDomain(
          indicatorStart,
          indicatorEnd,
          domainStart,
          domainEnd,
        );
      } else {
        return indicatorStart >= domainStart && indicatorStart <= domainEnd;
      }
    });
  });

  return filteredIndicators;
}
